@startuml
skinparam shadowing false
skinparam classAttributeIconSize 0
skinparam packageStyle rectangle

class AbstractFactoryPatternDemo {
  void main()
}

class FactoryProducer {
  AbstractFactory getFactory()
}

abstract class AbstractFactory <<abstract>> {
  Shape getShape()
  Color getColor()
}

class ShapeFactory {
  Shape getShape()
}

class ColorFactory {
  Color getColor()
}

interface Shape {
  void draw()
}

class Circle {
  void draw()
}
class Rectangle {
  void draw()
}
class Square {
  void draw()
}

interface Color {
  void fill()
}

class Blue {
  void fill()
}
class Green {
  void fill()
}
class Red {
  void fill()
}

AbstractFactoryPatternDemo --> FactoryProducer : ask
FactoryProducer --> AbstractFactory : make

ShapeFactory --|> AbstractFactory : extends
ColorFactory --|> AbstractFactory : extends

ShapeFactory --> Shape : create
ColorFactory --> Color : create

package "shape" {
  Shape
  Circle
  Rectangle
  Square
}

package "color" {
  Color
  Blue
  Green
  Red
}

Circle ..|> Shape : implement
Rectangle ..|> Shape : implement
Square ..|> Shape : implement

Blue ..|> Color : implement
Green ..|> Color : implement
Red ..|> Color : implement
@enduml
